I managed to integrate oscar with django cms using my own thumbnail template tag:

```
# web/templatetags/thumbnail.py

from django.template import Library
from easy_thumbnails.templatetags import thumbnail as easy_thumbnail
from oscar import OSCAR_MAIN_TEMPLATE_DIR
from sorl.thumbnail.templatetags import thumbnail as sorl_thumbnail


register = Library()


def thumbnail(parser, token):
    if parser.origin.name.startswith(OSCAR_MAIN_TEMPLATE_DIR):
        return sorl_thumbnail.thumbnail(parser, token)
    else:
        return easy_thumbnail.thumbnail(parser, token)


register.tag(thumbnail)
register.filter(easy_thumbnail.thumbnailer)
register.filter(easy_thumbnail.thumbnailer_passive)
register.filter(easy_thumbnail.thumbnail_url)
register.filter(easy_thumbnail.data_uri)

# settings.py

TEMPLATES = [
    {
        ...
        'OPTIONS': {
            ...
            'libraries': {
                'thumbnail': 'web.templatetags.thumbnail',
            }
        },
    },
]

```

